class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Convert all numbers to strings and store prefixes in sets
        prefixes1 = set()
        for num in arr1:
            s = str(num)
            for i in range(1, len(s) + 1):
                prefixes1.add(s[:i])

        prefixes2 = set()
        for num in arr2:
            s = str(num)
            for i in range(1, len(s) + 1):
                prefixes2.add(s[:i])

        # Find the longest common prefix
        max_len = 0
        for prefix in prefixes1:
            if prefix in prefixes2:
                max_len = max(max_len, len(prefix))

        return max_len
